                    if (prop.Value.ValueKind == JsonValueKind.Null)
                    {
                        continue;
                    }
                    dnsEndpointType = new StorageDnsEndpointType(prop.Value.GetString());
                    continue;
                }
                if (prop.NameEquals("isSkuConversionBlocked"u8))
                {
                    if (prop.Value.ValueKind == JsonValueKind.Null)
                    {
                        continue;
                    }
                    isSkuConversionBlocked = prop.Value.GetBoolean();
                    continue;
                }
                if (prop.NameEquals("accountMigrationInProgress"u8))
                {
                    if (prop.Value.ValueKind == JsonValueKind.Null)
                    {
                        continue;
                    }
                    isAccountMigrationInProgress = prop.Value.GetBoolean();
                    continue;
                }
                if (prop.NameEquals("geoPriorityReplicationStatus"u8))
                {
                    if (prop.Value.ValueKind == JsonValueKind.Null)
                    {
                        continue;
                    }
                    geoPriorityReplicationStatus = GeoPriorityReplicationStatus.DeserializeGeoPriorityReplicationStatus(prop.Value, options);
                    continue;
                }
                if (options.Format != "W")
                {
                    additionalBinaryDataProperties.Add(prop.Name, BinaryData.FromString(prop.Value.GetRawText()));
                }
            }
            return new StorageAccountProperties(
                provisioningState,
                primaryEndpoints,
                primaryLocation,
                statusOfPrimary,
                lastGeoFailoverOn,
                secondaryLocation,
                statusOfSecondary,
                createdOn,
                customDomain,
                sasPolicy,
                keyPolicy,
                keyCreationTime,
                secondaryEndpoints,
                encryption,
                accessTier,
                azureFilesIdentityBasedAuthentication,
                enableHttpsTrafficOnly,
                networkRuleSet,
                isSftpEnabled,
                isLocalUserEnabled,
                isExtendedGroupEnabled,
                isHnsEnabled,
                geoReplicationStats,
                isFailoverInProgress,
                largeFileSharesState,
                privateEndpointConnections ?? new ChangeTrackingList<StoragePrivateEndpointConnectionData>(),
                routingPreference,
                dualStackEndpointPreference,
                blobRestoreStatus,
                allowBlobPublicAccess,
                minimumTlsVersion,
                allowSharedKeyAccess,
                isNfsV3Enabled,
                allowCrossTenantReplication,
                isDefaultToOAuthAuthentication,
                publicNetworkAccess,
                immutableStorageWithVersioning,
                allowedCopyScope,
                storageAccountSkuConversionStatus,
                dnsEndpointType,
                isSkuConversionBlocked,
                isAccountMigrationInProgress,
                geoPriorityReplicationStatus,
                additionalBinaryDataProperties);
        }
    }
}
